export const STOCKS = [...new Map(_REAL_STOCKS.map(s => [s.symbol, s])).values()]
export const SECTORS = ['All', ...new Set(STOCKS.map(s => s.sector))]

export function getStock(symbol) {
  return STOCKS.find(s => s.symbol === symbol)
}
